function sendMailerSendEmail({ to, subject, html, fromName }) {
  return new Promise((resolve, reject) => {
    const apiKey = process.env.MAILERSEND_API_KEY;
    if (!apiKey) return reject(new Error('MAILERSEND_API_KEY not configured'));
    const body = JSON.stringify({
      from: { email: process.env.MAILERSEND_FROM_EMAIL || 'noreply@bookawaka.com', name: fromName || 'BookaWaka' },
      to: [{ email: to.email, name: to.name || to.email }],
      subject,
      html,
    });
    const req = https.request({
      hostname: 'api.mailersend.com',
      path: '/v1/email',
      method: 'POST',
      headers: {
        Authorization: 'Bearer ' + apiKey,
        'Content-Type': 'application/json',
        'Content-Length': Buffer.byteLength(body),
      },
    }, (res) => {
      let data = '';
      res.on('data', (c) => { data += c; });
      res.on('end', () => {
        if (res.statusCode >= 200 && res.statusCode < 300) resolve(data);
        else reject(new Error('MailerSend ' + res.statusCode + ': ' + data));
      });
    });
    req.on('error', reject);
    req.write(body);
    req.end();
  });
}

function syncCompanySettingsPlanBilling(companyId, plan, billingPatch, callback) {
  const now = Date.now();
  proxyFirebaseWrite('PATCH', 'companySettings/' + companyId + '/plan', Object.assign({}, plan, { updatedAt: now }), (err1) => {
    if (err1) return callback(err1);
    if (!billingPatch) return callback(null);
    proxyFirebaseWrite('PATCH', 'companySettings/' + companyId + '/billing', Object.assign({}, billingPatch, { updatedAt: now }), callback);
  });
}

function normTaxiVehicleId(v) {
  return String(v || '').trim().toUpperCase();
}

/** Canonical vehicle list from driver profile — assignedVehicles array first, legacy object-map read-only. */
function driverAssignedVehicleList(profile) {
  const out = [];
  if (!profile || typeof profile !== 'object') return out;
  const add = (v) => {
    const n = normTaxiVehicleId(v);
    if (n && !out.includes(n)) out.push(n);
  };
  if (Array.isArray(profile.assignedVehicles)) {
    profile.assignedVehicles.forEach(add);
  }
  const legacy = profile.allocatedVehicles;
  if (!out.length && legacy && typeof legacy === 'object' && !Array.isArray(legacy)) {
    Object.keys(legacy).forEach(k => { if (legacy[k]) add(k); });
  }
  if (!out.length && profile.allocatedTaxi) add(profile.allocatedTaxi);
  if (!out.length && profile.vehicleId) add(profile.vehicleId);
  return out;
}

