const FIREBASE_SCRIPTS = `
<script src="https://www.gstatic.com/firebasejs/9.22.2/firebase-app-compat.js"></script>
<script src="https://www.gstatic.com/firebasejs/9.22.2/firebase-auth-compat.js"></script>
<script src="https://www.gstatic.com/firebasejs/9.22.2/firebase-database-compat.js"></script>
<script src="https://www.gstatic.com/firebasejs/9.22.2/firebase-storage-compat.js"></script>
<script src="firebase-config.js"></script>
<script>
  // Restore and LOCK company ID from sessionStorage before any Firebase listeners start.
  // Always defines COMPANY_ID on window — even if sessionStorage is null — so that
  // Firebase callbacks never see a ReferenceError. The getter reads sessionStorage live
  // so it updates automatically once the auth flow stores bw_cid.
  (function(){
    var _fallback = '';
    try { _fallback = sessionStorage.getItem('bw_cid') || localStorage.getItem('bw_cid') || ''; } catch(e) {}
    // Seed session from server-injected bw_cid cookie (withCid) when storage is empty.
    if (!_fallback && typeof COMPANY_ID !== 'undefined' && COMPANY_ID && /^\\d+$/.test(String(COMPANY_ID))) {
      _fallback = String(COMPANY_ID);
    }
    window._bwStoreCompanyId = function(cid) {
      if (!cid || !/^\\d+$/.test(String(cid))) return;
      cid = String(cid);
      try { sessionStorage.setItem('bw_cid', cid); localStorage.setItem('bw_cid', cid); } catch(e) {}
      _fallback = cid;
    };
    if (_fallback) window._bwStoreCompanyId(_fallback);
    try {
      Object.defineProperty(window, 'COMPANY_ID', {
        get: function() {
          var v = '';
          try { v = sessionStorage.getItem('bw_cid') || localStorage.getItem('bw_cid') || ''; } catch(e) {}
          return v || _fallback || '';
        },
        set: function() { /* locked — page scripts cannot override with the env fallback */ },
        configurable: false,
        enumerable: true
      });
    } catch(defErr) {
      // Property already defined (e.g. var COMPANY_ID='1216' injected server-side).
      // Only overwrite if sessionStorage has a better (non-empty) value.
      if (_fallback) {
        try { window.COMPANY_ID = _fallback; } catch(e2) {}
      }
    }
  })();

  // Keep sessionStorage/localStorage bw_cid and HttpOnly bw_cid cookie aligned with the active company.
  window._bwEnsureSessionCompanyId = function(companyId) {
    var cid = String(companyId || '').trim();
    if (!cid || !/^\\d+$/.test(cid)) {
      console.warn('[bw_cid] _bwEnsureSessionCompanyId skipped — invalid companyId:', companyId);
      return Promise.resolve(false);
    }
    window._bwStoreCompanyId(cid);
    console.log('[bw_cid] storage bw_cid set to', cid);
    var tokP = (fbAuth && fbAuth.currentUser)
      ? fbAuth.currentUser.getIdToken().catch(function() { return null; })
      : Promise.resolve(null);
    return tokP.then(function(tok) {
      return fetch('/api/sync-session-company', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ companyId: cid, token: tok || undefined })
      });
    }).then(function(r) { return r.json(); }).then(function(res) {
      if (res && res.ok) {
        console.log('[bw_cid] bw_cid cookie synced to', cid);
        return true;
      }
      console.warn('[bw_cid] cookie sync failed:', (res && res.error) || 'unknown');
      return false;
    }).catch(function(e) {
      console.warn('[bw_cid] cookie sync request failed:', e && e.message);
      return false;
    });
  };
  firebase.initializeApp(FIREBASE_CONFIG);
  var fbAuth    = firebase.auth();
  var fbDB      = firebase.database();
  var fbStorage = firebase.storage();

  // Global node list — populated once per session via REST shallow query
  window.FB_NODES = null;

  // Discover the actual top-level node names in the Firebase DB using the
  // REST API shallow read (?shallow=true returns only keys, not all data).
  // This works even when SDK root read is blocked by security rules.
  function discoverDbNodes(user) {
    var cacheKey = 'fb_nodes_v2_' + (FIREBASE_CONFIG.projectId || 'bookawaka2026-564e1');
    try {
      var cached = sessionStorage.getItem(cacheKey);
      if (cached) {
        var parsed = JSON.parse(cached);
        // Only use cache if it has real data
        if (Array.isArray(parsed) && parsed.length > 0) {
          window.FB_NODES = parsed;
          console.log('[BookaWaka] Cached DB nodes (' + parsed.length + '):', parsed);
          return Promise.resolve(window.FB_NODES);
        }
      }
    } catch(e) {}

    return user.getIdToken(true).then(function(token) {
      var dbUrl = (FIREBASE_CONFIG.databaseURL || 'https://bookawaka2026-564e1-default-rtdb.firebaseio.com').replace(/\\/$/, '');
      // Use our server-side proxy to avoid browser CORS restrictions
      return fetch('/api/db-nodes?token=' + encodeURIComponent(token) + '&db=' + encodeURIComponent(dbUrl));
    }).then(function(resp) {
      return resp.json();
    }).then(function(data) {
      var keys = (data && data.keys && Array.isArray(data.keys)) ? data.keys : [];
      if (data && data.err) console.warn('[BookaWaka] DB discovery warning:', data.err);
      window.FB_NODES = keys;
      // Only cache non-empty results
      if (keys.length > 0) {
        try { sessionStorage.setItem(cacheKey, JSON.stringify(keys)); } catch(e) {}
      }
      console.log('[BookaWaka] Discovered DB nodes (' + keys.length + '):', keys);
      return keys;
    }).catch(function(err) {
      console.warn('[BookaWaka] Node discovery failed:', err.message || err);
      window.FB_NODES = [];
      return [];
    });
  }

  // Expose on window so page-level scripts can call it (e.g. Refresh button)
  window.discoverDbNodes = discoverDbNodes;

  // Auth guard — redirect to login if not signed in.
  // Also re-verifies company ID if sessionStorage lost it (e.g. cross-iframe navigation).
  // Discovers real node names before firing page-level data load.
  fbAuth.onAuthStateChanged(function(user) {
    var page = window.location.pathname.toLowerCase().replace(/.*\\//, '').split('?')[0];
    if (!user && page !== 'ownerlogin.aspx') {
      window.location.href = 'OwnerLogin.aspx';
      return;
    }
    if (user) {
      // If COMPANY_ID is empty (sessionStorage cleared or missing), re-verify from server
      // so every page has the correct company context even without a fresh login.
      var cidNow = '';
      try { cidNow = sessionStorage.getItem('bw_cid') || localStorage.getItem('bw_cid') || ''; } catch(e) {}
      if (!cidNow) {
        user.getIdToken().then(function(tok) {
          return fetch('/api/verify-admin', {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({ token: tok })
          }).then(function(r) { return r.json(); });
        }).then(function(res) {
          if (res.ok && res.companyId) {
            if (window._bwStoreCompanyId) window._bwStoreCompanyId(String(res.companyId));
            else try { sessionStorage.setItem('bw_cid', String(res.companyId)); localStorage.setItem('bw_cid', String(res.companyId)); } catch(e) {}
            return user.getIdToken().then(function(tok) {
              return fetch('/api/sync-session-company', {
                method: 'POST',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify({ companyId: String(res.companyId), token: tok })
              }).catch(function() {});
            });
          }
        }).catch(function(){}).finally(function() {
          discoverDbNodes(user).then(function() {
            if (window._fbOnLogin) window._fbOnLogin(user);
          });
        });
        return; // wait for re-verify, then _fbOnLogin
      }
      discoverDbNodes(user).then(function() {
        if (window._fbOnLogin) window._fbOnLogin(user);
      });
    }
  });

  // Admin write helper — routes writes through server-side proxy to bypass Firebase security rules
  window.adminWrite = function(nodePath, method, data) {
    return fetch('/api/admin-write', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ path: nodePath, method: method, data: data || null })
    }).then(function(r) { return r.json(); }).then(function(res) {
      if (res.error) throw new Error(res.error);
      return res;
    });
  };

  // Admin read helper — routes reads through server-side proxy to bypass Firebase security rules
  window.adminRead = function(nodePath, opts) {
    var url = '/api/admin-read?path=' + encodeURIComponent(nodePath);
    if (opts && opts.limitToLast) url += '&limitToLast=' + opts.limitToLast;
    if (opts && opts.orderBy)     url += '&orderBy='     + encodeURIComponent(opts.orderBy);
    if (opts && opts.shallow)     url += '&shallow=true';
    return fetch(url)
      .then(function(r) { return r.json(); })
      .then(function(res) {
        if (res.error) throw new Error(res.error);
        return res.data; // null if node is empty
      });
  };

  // Card commission / payout helpers — reads companies/{cid}/cardSettings
  window._cardSettingsCache = null;
  window.loadCardSettings = function() {
    var cid = window.COMPANY_ID || '';
    if (!cid) return Promise.resolve(window._cardSettingsCache = {});
    return window.adminRead('companies/' + cid + '/cardSettings').then(function(d) {
      window._cardSettingsCache = d || {};
      return window._cardSettingsCache;
    }).catch(function() {
      window._cardSettingsCache = {};
      return window._cardSettingsCache;
    });
  };
  window.isCardPaymentMethod = function(pm) {
    var s = String(pm || '').toLowerCase().replace(/[\s_-]/g, '');
    if (!s || s === '—' || s === '-') return false;
    if (s.indexOf('cash') !== -1) return false;
    if (s.indexOf('account') !== -1 || s === 'acc') return false;
    if (s.indexOf('mobility') !== -1 || s === 'tm') return false;
    if (s.indexOf('gift') !== -1) return false;
    return s.indexOf('card') !== -1 || s.indexOf('stripe') !== -1 || s.indexOf('eftpos') !== -1
      || s.indexOf('visa') !== -1 || s.indexOf('master') !== -1 || s.indexOf('amex') !== -1
      || s.indexOf('debit') !== -1 || s.indexOf('credit') !== -1;
  };
  window.calcCardPayout = function(fareNum, paymentMethod) {
    var gross = parseFloat(fareNum) || 0;
    if (gross <= 0) {
      return { gross: 0, commission: 0, net: 0, isCard: false, grossStr: '—', commissionStr: '—', netStr: '—' };
    }
    var cs = window._cardSettingsCache || {};
    if (!window.isCardPaymentMethod(paymentMethod)) {
      return {
        gross: gross, commission: 0, net: gross, isCard: false,
        grossStr: '$' + gross.toFixed(2), commissionStr: '—', netStr: '$' + gross.toFixed(2)
      };
    }
    var compPct = parseFloat(cs.companyPercent) || 0;
    var drvPct = parseFloat(cs.driverPercent) || 0;
    var compFee = gross * compPct / 100;
    var drvFee = gross * drvPct / 100;
    var commission = compFee + drvFee;
    var net = Math.max(0, gross - commission);
    return {
      gross: gross, commission: commission, net: net, isCard: true,
      compFee: compFee, drvFee: drvFee,
      grossStr: '$' + gross.toFixed(2),
      commissionStr: commission > 0 ? '$' + commission.toFixed(2) : '—',
      netStr: '$' + net.toFixed(2)
    };
  };

  // Realtime listener — uses Firebase client SDK so data streams live from the DB
  // Returns the Firebase ref so caller can call ref.off() to stop listening
  window.adminListen = function(nodePath, callback) {
    var ref = fbDB.ref(nodePath);
    ref.on('value', function(snap) {
      try { callback(snap.val()); } catch(e) { console.warn('[adminListen] callback error on', nodePath + ':', e); }
    }, function(err) {
      console.warn('[adminListen] permission error on', nodePath, '— falling back to REST polling');
      // Fall back to REST polling every 30s so the UI stays live even without direct DB access
      function _poll() {
        window.adminRead(nodePath).then(function(data) {
          try { callback(data); } catch(e) { console.warn('[adminListen] REST-callback error on', nodePath + ':', e); }
        }).catch(function(e) {
          console.warn('[adminListen] REST-read failed for', nodePath + ':', e);
        });
      }
      _poll(); // immediate first read
      var _pollTimer = setInterval(_poll, 30 * 1000);
      // Attach timer to ref so callers can cancel it via ref.off() equivalent
      ref._restPollTimer = _pollTimer;
    });
    return ref;
  };

  // Realtime listener limited to the N most recent entries (for large nodes like joback)
  window.adminListenLast = function(nodePath, n, callback) {
    var ref = fbDB.ref(nodePath).limitToLast(n);
    ref.on('value', function(snap) {
      try { callback(snap.val()); } catch(e) { console.warn('[adminListenLast] callback error:', e); }
    }, function(err) {
      console.warn('[adminListenLast] permission error on', nodePath, '— falling back to REST read');
      window.adminRead(nodePath).then(callback).catch(function(){});
    });
    return ref;
  };

  // Push a broadcast notification to all apps (driver, passenger, dispatch)
  // Writes to notification/{COMPANY_ID}/{key} — the path all apps listen to
  window.pushAdminNotif = function(message, senderLabel) {
    var cid = (typeof COMPANY_ID !== 'undefined') ? COMPANY_ID : '${process.env.COMPANY_ID || ""}';
    var now = new Date();
    var key = 'adm_' + now.getTime() + '_' + Math.random().toString(36).substr(2, 6).toUpperCase();
    var sender = senderLabel || 'Admin';
    var data = {
      DateTime:   now.toISOString(),
      DriverId:   'ALL',
      Message:    message,
      SenderName: sender,
      VehicleId:  'ALL',
      bookingid:  'admin,' + message + ',' + now.toLocaleDateString('en-NZ') + ',' + now.toLocaleTimeString('en-NZ',{hour:'2-digit',minute:'2-digit'}) + ',' + cid + ',ALL',
      content:    message,
      type:       'admin_broadcast',
      timestamp:  now.getTime()
    };
    return window.adminWrite('notification/' + cid + '/' + key, 'PUT', data)
      .catch(function(e) { console.warn('[pushAdminNotif] failed:', e.message); });
  };

  window.resolveNode = function(candidates) {
    var known = window.FB_NODES;
    if (!known || !known.length) return null;
    // 1. Exact match
    for (var i = 0; i < candidates.length; i++) {
      if (known.indexOf(candidates[i]) !== -1) return candidates[i];
    }
    // 2. Case-insensitive match
    var knownLower = known.map(function(k){ return k.toLowerCase(); });
    for (var j = 0; j < candidates.length; j++) {
      var idx = knownLower.indexOf(candidates[j].toLowerCase());
      if (idx !== -1) return known[idx];
    }
    // 3. Partial fuzzy match (candidate substring of key or vice versa)
    for (var c = 0; c < candidates.length; c++) {
      var cl = candidates[c].toLowerCase();
      for (var k = 0; k < known.length; k++) {
        var kl = known[k].toLowerCase();
        if (kl.includes(cl) || cl.includes(kl)) return known[k];
      }
    }
    return null;
  };
</script>`;

