  const js = `
<script>
var COMPANY_ID = '${COMPANY_ID}';
var _allMessages = {};
var _qrData = { dispatcher: [], driver: [] };
var _mediaFile = null, _mediaType = null;
var _msgRefreshTimer = null;

window._fbOnLogin = function(user) {
  document.getElementById('lblName').textContent = user.email || user.displayName || '';
  document.getElementById('header-user-email').textContent = user.email || '';
  loadMessages();
  loadQuickReplies();
};

/* ── Tab switching ─────────────────────────────────────────────────── */
function switchMsgTab(t) {
  ['history','quickreply'].forEach(function(id) {
    document.getElementById('tab-'+id).style.display = (id===t) ? '' : 'none';
    var btn = document.getElementById('tab-'+id+'-btn');
    if (btn) btn.classList.toggle('active', id===t);
  });
}

/* ── Helpers ───────────────────────────────────────────────────────── */
function escHtml(s) {
  return String(s||'').replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;');
}
function fmtTime(ts) {
  if (!ts) return '—';
  return new Date(ts).toLocaleString('en-NZ',{timeZone:NZ_TZ,day:'2-digit',month:'short',hour:'2-digit',minute:'2-digit'});
}
function showAlert(id, msg, type) {
  var el = document.getElementById(id);
  if (!el) return;
  el.style.display = 'block';
  el.style.background = type==='ok' ? '#E8F5E9' : type==='warn' ? '#FFF8E1' : '#FFEBEE';
  el.style.borderLeft  = '4px solid ' + (type==='ok' ? '#4CAF50' : type==='warn' ? '#FFC107' : '#F44336');
  el.style.color       = type==='ok' ? '#1B5E20' : type==='warn' ? '#5D4037' : '#B71C1C';
  el.textContent = msg;
  if (type==='ok') setTimeout(function(){ el.style.display='none'; }, 4000);
}

/* ── Message History ───────────────────────────────────────────────── */
function loadMessages() {
  window.adminRead('messages/' + COMPANY_ID).then(function(data) {
    _allMessages = data || {};
    renderMessages(_allMessages);
    var count = Object.keys(_allMessages).length;
    document.getElementById('msg-live-badge').textContent = count + ' message' + (count!==1?'s':'');
  }).catch(function(e) {
    document.getElementById('msg-feed').innerHTML =
      '<div style="text-align:center;color:#F44336;padding:30px;font-size:13px">Could not load messages: '+escHtml(e.message||e)+'</div>';
  });
  if (_msgRefreshTimer) clearInterval(_msgRefreshTimer);
  _msgRefreshTimer = setInterval(function() {
    window.adminRead('messages/' + COMPANY_ID).then(function(d) {
      _allMessages = d || {};
      applyMsgFilter();
      var c = Object.keys(_allMessages).length;
      document.getElementById('msg-live-badge').textContent = c + ' message' + (c!==1?'s':'');
    }).catch(function(){});
  }, 30000);
}

function applyMsgFilter() {
  var dFilter = (document.getElementById('filter-driver').value||'').toLowerCase().trim();
  var sFilter = (document.getElementById('filter-search').value||'').toLowerCase().trim();
  var fFilter = document.getElementById('filter-from').value;
  var dateFilter = document.getElementById('filter-date').value;
  var filtered = {};
  Object.entries(_allMessages).forEach(function(e) {
    var k=e[0], m=e[1]||{};
    if (dFilter && !(m.to||'').toLowerCase().includes(dFilter) && !(m.senderId||'').toLowerCase().includes(dFilter)) return;
    if (sFilter && !(m.text||'').toLowerCase().includes(sFilter)) return;
    if (fFilter && m.from !== fFilter) return;
    if (dateFilter) {
      var d = new Date(m.timestamp||0).toLocaleDateString('en-CA',{timeZone:NZ_TZ});
      if (d !== dateFilter) return;
    }
    filtered[k] = m;
  });
  renderMessages(filtered);
}

function clearMsgFilter() {
  ['filter-driver','filter-search','filter-date'].forEach(function(id){
    var el = document.getElementById(id); if(el) el.value='';
  });
  document.getElementById('filter-from').value = '';
  renderMessages(_allMessages);
}

function renderMessages(data) {
  var feed = document.getElementById('msg-feed');
  var entries = Object.entries(data||{});
  if (!entries.length) {
    feed.innerHTML = '<div style="text-align:center;color:#b0bec5;padding:50px 0;font-size:13px"><i class="material-icons" style="font-size:36px;display:block;margin:0 auto 8px;color:#e0e0e0">&#xE0C9;</i>No messages yet</div>';
    return;
  }
  entries.sort(function(a,b){ return (a[1].timestamp||0)-(b[1].timestamp||0); });
  feed.innerHTML = entries.map(function(e) {
    var m = e[1]||{};
    var isOut = (m.from==='dispatcher');
    var avatarBg = isOut ? '#1976D2' : '#388E3C';
    var initials = (m.senderName||m.from||'?').substring(0,2).toUpperCase();
    var avatar = '<div class="msg-avatar" style="background:'+avatarBg+'">'+escHtml(initials)+'</div>';
    var toLabel = m.to && m.to!=='all' ? ' <span style="font-size:10px;background:#e3f2fd;color:#1565c0;border-radius:4px;padding:1px 5px">→ '+escHtml(m.to)+'</span>' : (m.to==='all' ? ' <span style="font-size:10px;background:#f3e5f5;color:#6a1b9a;border-radius:4px;padding:1px 5px">→ All</span>' : '');
    var mediaHtml = '';
    if (m.mediaUrl) {
      if (m.mediaType==='image') mediaHtml = '<a href="'+escHtml(m.mediaUrl)+'" target="_blank"><img class="msg-media-thumb" src="'+escHtml(m.mediaUrl)+'"/></a>';
      else if (m.mediaType==='video') mediaHtml = '<video class="msg-media-thumb" controls src="'+escHtml(m.mediaUrl)+'"></video>';
      else if (m.mediaType==='audio') mediaHtml = '<audio controls style="max-width:200px;display:block;margin-top:4px" src="'+escHtml(m.mediaUrl)+'"></audio>';
    }
    var textPart = m.text ? '<div class="msg-text">'+escHtml(m.text)+'</div>' : '';
    return '<div class="msg-bubble '+(isOut?'out':'in')+'">' +
      avatar +
      '<div class="msg-body">' +
        textPart + mediaHtml +
        '<div class="msg-meta">'+escHtml(m.senderName||m.from||'?')+toLabel+' · '+fmtTime(m.timestamp)+'</div>' +
      '</div>' +
    '</div>';
  }).join('');
  feed.scrollTop = feed.scrollHeight;
}

/* ── Export CSV ────────────────────────────────────────────────────── */
function exportMsgCsv() {
  var rows = [['DateTime','From','SenderName','To','Message','MediaType','MediaUrl']];
  Object.values(_allMessages).sort(function(a,b){return (a.timestamp||0)-(b.timestamp||0);}).forEach(function(m) {
    rows.push([
      new Date(m.timestamp||0).toISOString(),
      m.from||'', m.senderName||'', m.to||'', (m.text||'').replace(/,/g,' '),
      m.mediaType||'', m.mediaUrl||''
    ]);
  });
  var csv = rows.map(function(r){return r.map(function(c){return '"'+String(c).replace(/"/g,'""')+'"';}).join(',');}).join('\\n');
  var a = document.createElement('a');
  a.href = 'data:text/csv;charset=utf-8,' + encodeURIComponent(csv);
  a.download = 'messages_'+COMPANY_ID+'_'+new Date().toISOString().slice(0,10)+'.csv';
  a.click();
}

/* ── Media picker ──────────────────────────────────────────────────── */
function handleMediaPick(input, type) {
  var file = input.files[0];
  if (!file) return;
  _mediaFile = file; _mediaType = type;
  var preview = document.getElementById('media-preview');
  preview.style.display = 'block';
  var url = URL.createObjectURL(file);
  var inner = '';
  if (type==='image') inner = '<img src="'+url+'" style="max-width:120px;max-height:80px;border-radius:6px"/>';
  else if (type==='video') inner = '<video src="'+url+'" style="max-width:120px;max-height:80px;border-radius:6px" controls></video>';
  else inner = '<audio src="'+url+'" controls style="max-width:200px"></audio>';
  preview.innerHTML = '<div class="media-preview-wrap">'+inner+'<button class="rm-media" onclick="clearMedia()">×</button></div><div style="font-size:11px;color:#78909c;margin-top:3px">'+escHtml(file.name)+'</div>';
}

function clearMedia() {
  _mediaFile = null; _mediaType = null;
  var p = document.getElementById('media-preview');
  p.style.display='none'; p.innerHTML='';
  ['media-pick-image','media-pick-video','media-pick-audio'].forEach(function(id){
    var el=document.getElementById(id); if(el) el.value='';
  });
}

/* ── Send Message ──────────────────────────────────────────────────── */
function sendMessage() {
  var text   = (document.getElementById('compose-text').value||'').trim();
  var sender = (document.getElementById('compose-sender').value||'').trim() || 'Dispatch';
  var from   = document.getElementById('compose-from').value;
  var to     = (document.getElementById('compose-to').value||'').trim() || 'all';
  if (!text && !_mediaFile) { showAlert('compose-alert','Please enter a message or attach media.','err'); return; }
  var btn = document.getElementById('compose-send-btn');
  btn.disabled=true; btn.innerHTML='<i class="material-icons" style="font-size:16px">&#xE01D;</i> Sending…';

  var doSend = function(mediaUrl, mediaType) {
    var key = 'msg_' + Date.now() + '_' + Math.random().toString(36).substr(2,6);
    var record = {
      from: from, senderName: sender, to: to,
      text: text, timestamp: Date.now(),
      mediaUrl: mediaUrl||null, mediaType: mediaType||null
    };
    return window.adminWrite('messages/' + COMPANY_ID + '/' + key, 'PUT', record);
  };

  var finish = function() {
    btn.disabled=false;
    btn.innerHTML='<i class="material-icons" style="font-size:16px">&#xE163;</i> Send Message';
  };

  if (_mediaFile) {
    showAlert('compose-alert','Uploading media…','warn');
    var storageRef = fbStorage.ref('messages/' + COMPANY_ID + '/' + Date.now() + '_' + _mediaFile.name);
    storageRef.put(_mediaFile).then(function(snap) {
      return snap.ref.getDownloadURL();
    }).then(function(url) {
      return doSend(url, _mediaType);
    }).then(function() {
      showAlert('compose-alert','Message sent.','ok');
      document.getElementById('compose-text').value='';
      clearMedia();
      loadMessages();
    }).catch(function(e) {
      showAlert('compose-alert','Upload failed: '+escHtml(e.message||e),'err');
    }).finally(finish);
  } else {
    doSend(null,null).then(function() {
      showAlert('compose-alert','Message sent.','ok');
      document.getElementById('compose-text').value='';
      loadMessages();
    }).catch(function(e) {
      showAlert('compose-alert','Send failed: '+escHtml(e.message||e),'err');
    }).finally(finish);
  }
}

/* ── Quick Replies ─────────────────────────────────────────────────── */
function loadQuickReplies() {
  window.adminRead('quickReplies/' + COMPANY_ID).then(function(data) {
    _qrData.dispatcher = (data && data.dispatcher) ? (Array.isArray(data.dispatcher) ? data.dispatcher : Object.values(data.dispatcher)) : [];
    _qrData.driver     = (data && data.driver)     ? (Array.isArray(data.driver)     ? data.driver     : Object.values(data.driver))     : [];
    if (!_qrData.dispatcher.length) _qrData.dispatcher = ['How long will you be?','Please call the office','Job has been cancelled','On your way?'];
    if (!_qrData.driver.length)     _qrData.driver     = ['5 mins','10 mins','Here now','On my way','Running late','No show'];
    renderQr();
    renderComposeChips();
  }).catch(function() {
    _qrData.dispatcher = ['How long will you be?','Please call the office','Job has been cancelled','On your way?'];
    _qrData.driver     = ['5 mins','10 mins','Here now','On my way','Running late','No show'];
    renderQr();
    renderComposeChips();
  });
}

function renderQr() {
  ['dispatcher','driver'].forEach(function(side) {
    var id = side==='dispatcher' ? 'qr-disp-list' : 'qr-driv-list';
    var el = document.getElementById(id); if (!el) return;
    if (!_qrData[side].length) { el.innerHTML='<span style="font-size:12px;color:#b0bec5">No templates yet</span>'; return; }
    el.innerHTML = _qrData[side].map(function(t,i) {
      return '<span class="qr-chip">'+escHtml(t)+'<button class="qr-del" data-side="'+side+'" data-idx="'+i+'" onclick="removeQr(this.dataset.side,+this.dataset.idx)" title="Remove">\xD7</button></span>';
    }).join('');
  });
}

function renderComposeChips() {
  var from = document.getElementById('compose-from');
  var side = from ? from.value : 'dispatcher';
  var chips = _qrData[side]||[];
  var el = document.getElementById('compose-quickchips'); if (!el) return;
  if (!chips.length) { el.innerHTML='<span style="font-size:11px;color:#b0bec5">No templates. Add them in the Quick Reply Templates tab.</span>'; return; }
  el.innerHTML = chips.map(function(t) {
    return '<button onclick="useQuickReply(this)" data-text="'+escHtml(t)+'" '+
      'style="border:1.5px solid #1976D2;background:#e3f2fd;border-radius:16px;padding:4px 12px;font-size:11px;color:#1565c0;cursor:pointer;margin:2px;white-space:nowrap">'+
      escHtml(t)+'</button>';
  }).join('');
}

function useQuickReply(btn) {
  var t = document.getElementById('compose-text');
  if (t) t.value = btn.getAttribute('data-text');
  t.focus();
}

function addQr(side) {
  var inputId = side==='dispatcher' ? 'qr-disp-input' : 'qr-driv-input';
  var el = document.getElementById(inputId); if (!el) return;
  var val = el.value.trim();
  if (!val) return;
  if (_qrData[side].includes(val)) { showAlert('qr-alert','That template already exists.','warn'); return; }
  _qrData[side].push(val);
  el.value='';
  renderQr();
}

function removeQr(side, idx) {
  _qrData[side].splice(idx,1);
  renderQr();
}

function saveQuickReplies() {
  var btn = document.getElementById('qr-save-btn');
  btn.disabled=true; btn.textContent='Saving…';
  window.adminWrite('quickReplies/' + COMPANY_ID, 'PUT', _qrData).then(function() {
    showAlert('qr-alert','Templates saved.','ok');
    renderComposeChips();
  }).catch(function(e) {
    showAlert('qr-alert','Save failed: '+escHtml(e.message||e),'err');
  }).finally(function() {
    btn.disabled=false; btn.textContent='Save Templates';
  });
}

// Update compose chips when "Send As" changes
document.addEventListener('DOMContentLoaded', function() {
  var sel = document.getElementById('compose-from');
  if (sel) sel.addEventListener('change', renderComposeChips);
});
</script>`;

